// Kernel Density Estimation using Gaussian Kernel
function kernelDensityEstimator(kernel, x) {
  return function(sample) {
    return x.map(function(v) {
      var meanD = 0;
      for (var i = 0; i < sample.length; i++) {
        meanD += kernel(v - sample[i]);
      }
      return [v, meanD / sample.length];
    });
  };
}

function kernelGaussian(threshold) {
  return function(v) {
    return Math.exp(-v * v / (2 * threshold * threshold)) / (Math.sqrt(2 * Math.PI) * threshold);
  };
}

function getMean(values) {
  var sum = 0;
  for (var i = 0; i < values.length; i++) sum += values[i];
  return sum / values.length;
}

function getDeviation(values) {
  var mean = getMean(values);
  var sumSq = 0;
  for (var i = 0; i < values.length; i++) sumSq += Math.pow(values[i] - mean, 2);
  return Math.sqrt(sumSq / (values.length - 1));
}

// Silverman's Rule for bandwidth
function silvermanBandwidth(values) {
  var n = values.length;
  var std = getDeviation(values);
  return 1.06 * std * Math.pow(n, -0.2);
}

var categories = rawData.categories;
var allValues = [];
categories.forEach(function(c) { allValues = allValues.concat(c.values); });

var minVal = Math.min.apply(null, allValues);
var maxVal = Math.max.apply(null, allValues);
var range = maxVal - minVal;

// Calculate max bandwidth to guarantee sufficient padding
var maxBw = 0;
categories.forEach(function(cat) {
  var b = silvermanBandwidth(cat.values);
  if (b > maxBw) maxBw = b;
});

// Padding to see the tails properly (3 sigma)
var padTop = maxBw * 3;
var padBottom = maxBw * 3;
// Restrict minimum to 0 since fruit counts cannot be negative
var effectiveMin = Math.max(0, minVal - padBottom);
var effectiveMax = maxVal + padTop;

var step = (effectiveMax - effectiveMin) / 100;
var xRange = [];
for (var v = effectiveMin; v <= effectiveMax; v += step) {
  xRange.push(v);
}
// Guard float ending point
if (xRange[xRange.length - 1] < effectiveMax) {
  xRange.push(effectiveMax);
}

transformedData = categories.map(function(cat) {
  var values = cat.values.slice().sort(function(a, b) { return a - b; });
  var bandwidth = silvermanBandwidth(values);
  var estimator = kernelDensityEstimator(kernelGaussian(bandwidth), xRange);
  var density = estimator(values);

  density.unshift([effectiveMin, 0]);
  density.push([effectiveMax, 0]);

  return {
    name: cat.name,
    density: density,
    min: effectiveMin,
    max: effectiveMax
  };
});

echarts_js:
var series = [];
var colors = ['#5470c6', '#91cc75', '#fac858', '#ee6666', '#73c0de', '#3ba272', '#fc8452', '#9a60b4', '#ea7ccc'];

transformedData.forEach(function(sd, idx) {
  var maxD = 0;
  for (var i = 0; i < sd.density.length; i++) {
    if (sd.density[i][1] > maxD) maxD = sd.density[i][1];
  }

  // Create polygon points for the violin shape
  var leftData = sd.density.map(function(d) { return [idx - (d[1] / maxD) * 0.4, d[0]]; });
  var rightData = sd.density.map(function(d) { return [idx + (d[1] / maxD) * 0.4, d[0]]; });
  rightData.reverse();
  var polygon = leftData.concat(rightData);

  series.push({
    type: 'custom',
    name: sd.name,
    renderItem: function(params, api) {
      if (params.dataIndex !== 0) return;
      var points = polygon.map(function(p) { return api.coord(p); });
      return {
        type: 'polygon',
        shape: { points: points },
        style: api.style({
          fill: colors[idx % colors.length],
          stroke: '#666',
          lineWidth: 1,
          opacity: 0.7
        })
      };
    }, transformation: function(params, api) {
       return { type: 'polygon', shape: { points: polygon.map(p => api.coord(p)) } };
    },
    data: [[idx, sd.min], [idx, sd.max]],
    tooltip: { show: true }
  });
});

option = {
  title: {
    text: 'Fruit Data Distribution (KDE)',
    left: 'center',
    top: 20
  },
  tooltip: {
    trigger: 'item',
    formatter: function(params) {
      return '<b>' + params.seriesName + '</b>';
    }
  },
  grid: {
    top: 80,
    bottom: 50,
    left: 80,
    right: 50
  },
  xAxis: {
    type: 'value',
    min: -0.5,
    max: transformedData.length - 0.5,
    axisLabel: {
      formatter: function(v) {
        var idx = Math.round(v);
        return transformedData[idx] ? transformedData[idx].name : '';
      }
    },
    splitLine: { show: false }
  },
  yAxis: {
    type: 'value',
    name: 'Value',
    scale: true,
    splitLine: {
      lineStyle: { type: 'dashed' }
    }
  },
  series: series
};
